191→        throw {status: 400, error:'parentid or userid is undefined'};
192→    }
193→    if(!opinion || !typeof(opinion) === 'string'){
194→        console.error('opinion is undefined or opinion is not a string')
195→        throw {status: 'opinion is undefined or opinion is not a string'};
196→    }
197→
198→    const {data: parentOpinion, error: errorParentOpinion} = await supabase
199→    .from('opinions')
200→    .select('user_id')
201→    .eq('id', parent_id)
202→    .maybeSingle();
203→
204→    if(errorParentOpinion){
205→        console.error('supabase error while fetching parent opinion', errorParentOpinion.message);
206→        throw {status: 500, error: 'supabase error while fetching parent opinion'};
207→    }
208→    if(!parentOpinion?.user_id){
209→        console.error('parent opinion not found');
210→        throw {status: 404, error: 'parent opinion not found'};
